const message = $('Telegram Trigger').first().json;

const chat_id = message.message?.chat?.id;
const texto = message.message?.text || '';
const nombre = message.message?.chat?.first_name || 'Cliente';
const apellido = message.message?.chat?.last_name || '';
const nombre_completo = (nombre + ' ' + apellido).trim();

return [{
  json: {
    chat_id: chat_id,
    texto: texto,
    nombre_telegram: nombre_completo,
    timestamp: new Date().toISOString()
  }
}];

const telegram = $('Extraer Datos Telegram').first().json;

// Lead puede venir de Buscar Lead o Crear Lead
let lead;
try {
  lead = $('Buscar Lead').first().json;
  if (!lead.fields) throw new Error();
} catch(e) {
  lead = $('Crear Lead').first().json;
}

// Conversación puede venir de 3 sitios
let conversacion_id = '';
let historial = '';

try {
  const conv = $('Crear Conversacion').first().json;
  if (!conv.id) throw new Error();
  conversacion_id = conv.id;
  historial = conv.fields?.['Historial Mensajes'] || '';
} catch(e) {
  try {
    const conv = $('Crear Conversacion Nueva').first().json;
    if (!conv.id) throw new Error();
    conversacion_id = conv.id;
    historial = conv.fields?.['Historial Mensajes'] || '';
  } catch(e2) {
    try {
      const conv = $('Buscar Conversacion').first().json;
      conversacion_id = conv.id || '';
      historial = conv.fields?.['Historial Mensajes'] || '';
    } catch(e3) {
      conversacion_id = '';
      historial = '';
    }
  }
}

return [{
  json: {
    chat_id: telegram.chat_id,
    texto_nuevo: telegram.texto,
    nombre: lead.fields['Nombre'] || telegram.nombre_telegram,
    lead_id: lead.fields['Lead ID'],
    lead_record_id: lead.id,
    estado_ciclo: lead.fields['Estado Ciclo'] || 'nuevo',
    presupuesto_min: lead.fields['Presupuesto Min'] || 0,
    presupuesto_max: lead.fields['Presupuesto Max'] || 0,
    zona: lead.fields['Zona Deseada'] || '',
    hipoteca: lead.fields['Hipoteca Estado'] || '',
    plazo: lead.fields['Plazo Compra'] || '',
    motivacion: lead.fields['Motivacion Real'] || '',
    conversacion_id: conversacion_id,
    historial: historial
  }
}];

const input = $input.first().json;
const raw = input.output[0].content[0].text;

// Limpia posibles backticks de markdown
const clean = raw.replace(/```json|```/g, '').trim();

const datos = JSON.parse(clean);

return [{
  json: {
    nombre: datos.nombre,
    presupuesto_min: datos.presupuesto_min,
    presupuesto_max: datos.presupuesto_max,
    zona: datos.zona,
    hipoteca: datos.hipoteca,
    plazo: datos.plazo,
    motivacion: datos.motivacion,
    perfil_completo: datos.perfil_completo
  }
}];
